import { Component, OnInit, ViewChild } from '@angular/core';

// Swiper Slider
import { SwiperOptions } from 'swiper';

@Component({
  selector: 'app-swiper',
  templateUrl: './swiper.component.html',
  styleUrls: ['./swiper.component.scss']
})

/**
 * Swiper Component
 */
export class SwipersComponent implements OnInit {

  // bread crumb items
  breadCrumbItems!: Array<{}>;

  constructor() { }

  ngOnInit(): void {
    /**
    * BreadCrumb
    */
     this.breadCrumbItems = [
      { label: 'Advance UI' },
      { label: 'Swiper Slider', active: true }
    ];
  }

  /**
   * Swiper setting
   */
   config = {
    initialSlide: 0,
    slidesPerView: 1,
  };

  /**
   * Swiper Nav&Pagination setting
   */
   NavAndPaginatoion = {
    initialSlide: 0,
    slidesPerView: 1,
    pagination: true,
    navigation: true
  };

  /**
   * Swiper Pagination setting
   */
   Paginatoion = {
    initialSlide: 0,
    slidesPerView: 1,
    pagination: true,
  };

  /**
   * Swiper Progress setting
   */
   Progress = {
    initialSlide: 0,
    slidesPerView: 1,
    navigation: true,
    scrollbar: true,
  };

